public final class BankingEngine {
    private let storage: BankingStorage
    private var state: BankingState
    private let queue = DispatchQueue(label: "com.example.banking.engine.queue", qos: .userInitiated)

    public init(storage: BankingStorage = EncryptedFileStorage()) throws {
        self.storage = storage
        self.state = try storage.loadState()
    }

    public func listAccounts() -> [Account] {
        queue.sync {
            Array(state.accounts.values).sorted { $0.displayName.localizedCaseInsensitiveCompare($1.displayName) == .orderedAscending }
        }
    }

    public func account(id: UUID) -> Account? {
        queue.sync { state.accounts[id] }
    }

    @discardableResult
    public func createAccount(displayName: String, currencyCode: String) throws -> Account {
        try queue.sync {
            let trimmed = displayName.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else { throw BankingError.invalidInput }
            let code = currencyCode.uppercased()
            guard code.count == 3 else { throw BankingError.invalidInput }

            let account = Account(displayName: trimmed, currencyCode: code, balanceCents: 0, updatedAt: Date())
            state.accounts[account.id] = account
            state.transactions[account.id] = []
            try storage.saveState(state)
            return account
        }
    }

    public func transactions(for accountId: UUID) throws -> [Transaction] {
        try queue.sync {
            guard state.accounts[accountId] != nil else { throw BankingError.accountNotFound }
            return (state.transactions[accountId] ?? []).sorted { $0.createdAt > $1.createdAt }
        }
    }

    public func deposit(accountId: UUID, amountCents: Int64, description: String? = nil) throws -> Transaction {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            guard var account = state.accounts[accountId] else { throw BankingError.accountNotFound }

            let tx = Transaction(accountId: accountId, type: .deposit, amountCents: amountCents, currencyCode: account.currencyCode, description: description)
            account.balanceCents = safeAdd(account.balanceCents, amountCents)
            account.updatedAt = Date()

            state.accounts[accountId] = account
            state.transactions[accountId, default: []].append(tx)

            try storage.saveState(state)
            return tx
        }
    }

    public func withdraw(accountId: UUID, amountCents: Int64, description: String? = nil) throws -> Transaction {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            guard var account = state.accounts[accountId] else { throw BankingError.accountNotFound }
            guard account.balanceCents >= amountCents else { throw BankingError.insufficientFunds }

            let tx = Transaction(accountId: accountId, type: .withdrawal, amountCents: amountCents, currencyCode: account.currencyCode, description: description)
            account.balanceCents = safeSub(account.balanceCents, amountCents)
            account.updatedAt = Date()

            state.accounts[accountId] = account
            state.transactions[accountId, default: []].append(tx)

            try storage.saveState(state)
            return tx
        }
    }

    public func transfer(from fromId: UUID, to toId: UUID, amountCents: Int64, description: String? = nil) throws -> (Transaction, Transaction) {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            guard fromId != toId else { throw BankingError.invalidInput }
            guard var from = state.accounts[fromId] else { throw BankingError.accountNotFound }
            guard var to = state.accounts[toId] else { throw BankingError.accountNotFound }
            guard from.currencyCode == to.currencyCode else { throw BankingError.currencyMismatch }
            guard from.balanceCents >= amountCents else { throw BankingError.insufficientFunds }

            let outTx = Transaction(accountId: fromId, type: .transferOut, amountCents: amountCents, currencyCode: from.currencyCode, description: description)
            let inTx = Transaction(accountId: toId, type: .transferIn, amountCents: amountCents, currencyCode: to.currencyCode, description: description)

            from.balanceCents = safeSub(from.balanceCents, amountCents)
            to.balanceCents = safeAdd(to.balanceCents, amountCents)
            let now = Date()
            from.updatedAt = now
            to.updatedAt = now

            state.accounts[fromId] = from
            state.accounts[toId] = to
            state.transactions[fromId, default: []].append(outTx)
            state.transactions[toId, default: []].append(inTx)

            try storage.saveState(state)
            return (outTx, inTx)
        }
    }

    private func safeAdd(_ a: Int64, _ b: Int64) -> Int64 {
        let (res, overflow) = a.addingReportingOverflow(b)
        if overflow { return Int64.max }
        return res
    }

    private func safeSub(_ a: Int64, _ b: Int64) -> Int64 {
        let (res, overflow) = a.subtractingReportingOverflow(b)
        if overflow { return Int64.min }
        return res
    }
}

