final class AccountsViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    private let engine: BankingEngine
    private let tableView = UITableView(frame: .zero, style: .insetGrouped)
    private var accounts: [Account] = []

    init(engine: BankingEngine) {
        self.engine = engine
        super.init(nibName: nil, bundle: nil)
        self.title = "Accounts"
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .add, target: self, action: #selector(addAccount))
        navigationItem.leftBarButtonItem = UIBarButtonItem(title: "Refresh", style: .plain, target: self, action: #selector(refresh))

        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.dataSource = self
        tableView.delegate = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "cell")

        view.addSubview(tableView)
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])

        refresh()
    }

    @objc private func refresh() {
        accounts = engine.listAccounts()
        tableView.reloadData()
    }

    @objc private func addAccount() {
        let vc = AccountCreateViewController { [weak self] name, currency in
            guard let self else { return }
            do {
                _ = try self.engine.createAccount(displayName: name, currencyCode: currency)
                self.refresh()
            } catch {
                self.presentAlert(title: "Error", message: error.localizedDescription)
            }
        }
        let nav = UINavigationController(rootViewController: vc)
        nav.modalPresentationStyle = .formSheet
        present(nav, animated: true)
    }

    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int { accounts.count }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let a = accounts[indexPath.row]
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        var cfg = cell.defaultContentConfiguration()
        cfg.text = a.displayName
        cfg.secondaryText = MoneyFormatter.string(amountCents: a.balanceCents, currencyCode: a.currencyCode)
        cell.contentConfiguration = cfg
        cell.accessoryType = .disclosureIndicator
        return cell
    }

    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let a = accounts[indexPath.row]
        let vc = AccountDetailViewController(engine: engine, accountId: a.id)
        navigationController?.pushViewController(vc, animated: true)
    }
}

final class AccountDetailViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    private let engine: BankingEngine
    private let accountId: UUID
    private var account: Account?
    private var txs: [Transaction] = []

    private let headerView = BalanceHeaderView()
    private let tableView = UITableView(frame: .zero, style: .insetGrouped)

    init(engine: BankingEngine, accountId: UUID) {
        self.engine = engine
        self.accountId = accountId
        super.init(nibName: nil, bundle: nil)
        self.title = "Account"
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        navigationItem.rightBarButtonItem = UIBarButtonItem(title: "New", style: .plain, target: self, action: #selector(newTransaction))
        navigationItem.leftBarButtonItem = UIBarButtonItem(title: "Refresh", style: .plain, target: self, action: #selector(refresh))

        headerView.translatesAutoresizingMaskIntoConstraints = false
        tableView.translatesAutoresizingMaskIntoConstraints = false

        tableView.dataSource = self
        tableView.delegate = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "txcell")

        view.addSubview(headerView)
        view.addSubview(tableView)

        NSLayoutConstraint.activate([
            headerView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            headerView.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            headerView.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),

            tableView.topAnchor.constraint(equalTo: headerView.bottomAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])

        refresh()
    }

    @objc private func refresh() {
        account = engine.account(id: accountId)
        if let account {
            headerView.configure(title: account.displayName, balance: MoneyFormatter.string(amountCents: account.balanceCents, currencyCode: account.currencyCode))
        } else {
            headerView.configure(title: "Unknown", balance: "--")
        }

        do {
            txs = try engine.transactions(for: accountId)
        } catch {
            txs = []
        }
        tableView.reloadData()
    }

    @objc private func newTransaction() {
        guard let account else { return }
        let vc = TransactionCreateViewController(engine: engine, account: account) { [weak self] in
            self?.refresh()
        }
        let nav = UINavigationController(rootViewController: vc)
        nav.modalPresentationStyle = .formSheet
        present(nav, animated: true)
    }

    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int { txs.count }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let tx = txs[indexPath.row]
        let cell = tableView.dequeueReusableCell(withIdentifier: "txcell", for: indexPath)
        var cfg = cell.defaultContentConfiguration()
        cfg.text = tx.type.rawValue
        if let account = account {
            let sign: String
            switch tx.type {
            case .deposit, .transferIn: sign = "+"
            case .withdrawal, .transferOut: sign = "-"
            }
            cfg.secondaryText = "\(sign)\(MoneyFormatter.string(amountCents: tx.amountCents, currencyCode: account.currencyCode)) • \(tx.createdAt.formatted(date: .abbreviated, time: .shortened))"
        } else {
            cfg.secondaryText = "\(tx.amountCents) • \(tx.createdAt)"
        }
        cell.contentConfiguration = cfg
        cell.selectionStyle = .none
        return cell
    }
}

