        let form = UIStackView(arrangedSubviews: [segmented, amountField, descField])
        form.axis = .vertical
        form.spacing = 12
        form.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(form)
        NSLayoutConstraint.activate([
            form.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            form.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor, constant: 16),
            form.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -16)
        ])
    }

    @objc private func cancel() { dismiss(animated: true) }

    @objc private func post() {
        do {
            let cents = try parseAmountToCents(amountField.text ?? "")
            let desc = (descField.text?.trimmingCharacters(in: .whitespacesAndNewlines)).flatMap { $0.isEmpty ? nil : $0 }
            if segmented.selectedSegmentIndex == 0 {
                _ = try engine.deposit(accountId: account.id, amountCents: cents, description: desc)
            } else {
                _ = try engine.withdraw(accountId: account.id, amountCents: cents, description: desc)
            }
            dismiss(animated: true) { [onDone] in onDone() }
        } catch {
            presentAlert(title: "Error", message: error.localizedDescription)
        }
    }

    private func parseAmountToCents(_ text: String) throws -> Int64 {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { throw BankingError.invalidAmount }

        let normalized = trimmed.replacingOccurrences(of: ",", with: ".")
        guard let decimal = Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")) else {
            throw BankingError.invalidAmount
        }
        if decimal <= 0 { throw BankingError.invalidAmount }
        let centsDecimal = (decimal * 100)
        var rounded = Decimal()
        var value = centsDecimal
        NSDecimalRound(&rounded, &value, 0, .bankers)
        let ns = rounded as NSDecimalNumber
        let cents = ns.int64Value
        guard cents > 0 else { throw BankingError.invalidAmount }
        return cents
    }
}

final class ErrorViewController: UIViewController {
    private let error: Error

    init(error: Error) {
        self.error = error
        super.init(nibName: nil, bundle: nil)
        self.title = "Error"
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        let label = UILabel()
        label.numberOfLines = 0
        label.textAlignment = .center
        label.text = error.localizedDescription
        label.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(label)
        NSLayoutConstraint.activate([
            label.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            label.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor, constant: 16),
            label.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -16)
        ])
    }
}

// MARK: - UIViewController Alerts

extension UIViewController {
    func presentAlert(title: String, message: String) {
        let ac = UIAlertController(title: title, message: message, preferredStyle: .alert)
        ac.addAction(UIAlertAction(title: "OK", style: .default))
        present(ac, animated: true)
    }
}

